import{_ as r,o as i,c as t,ai as e}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"SpringBoot 核心原理与自动装配","description":"","frontmatter":{},"headers":[],"relativePath":"framework/springboot-principle.md","filePath":"framework/springboot-principle.md"}'),n={name:"framework/springboot-principle.md"};function s(a,o,c,g,l,d){return i(),t("div",null,[...o[0]||(o[0]=[e('<h1 id="springboot-核心原理与自动装配" tabindex="-1">SpringBoot 核心原理与自动装配 <a class="header-anchor" href="#springboot-核心原理与自动装配" aria-label="Permalink to “SpringBoot 核心原理与自动装配”">​</a></h1><hr><h3 id="❓-面试官-spring-boot-和-spring-有什么区别-为什么要用-spring-boot" tabindex="-1">❓ 面试官：Spring Boot 和 Spring 有什么区别？为什么要用 Spring Boot？ <a class="header-anchor" href="#❓-面试官-spring-boot-和-spring-有什么区别-为什么要用-spring-boot" aria-label="Permalink to “❓ 面试官：Spring Boot 和 Spring 有什么区别？为什么要用 Spring Boot？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Spring 就像是一个庞大但需要自己组装的“毛坯房”，而 Spring Boot 是精装修的“拎包入住房”。<strong>Spring Boot 本质上还是 Spring</strong>，但它通过<strong>“约定大于配置”</strong>的理念，解决了 Spring 以前令人极其痛苦的<strong>繁琐 XML 配置</strong>和<strong>依赖包版本冲突</strong>两大痛点。</p><p><strong>📝 详细优势解析：</strong></p><ol><li><strong>起步依赖（Starter）</strong>：以前引入一个 Web 环境，要手动在 <code>pom.xml</code> 里找 Spring-Web、Spring-MVC、Jackson 等十几个包，还要小心翼翼对比版本号防冲突。现在只需要引入一个 <code>spring-boot-starter-web</code>，它自动帮你拉取所有测试兼容好的底层依赖。</li><li><strong>自动配置（Auto Configuration）</strong>：以前配个 MyBatis，要写一大堆 XML（配数据源、配 SqlSessionFactory）。现在只需在 <code>application.yml</code> 里写两行数据库账号密码，SpringBoot 会在启动时<strong>自动侦测</strong>并帮你把这些 Bean 注册到容器里。</li><li><strong>内嵌 Web 容器</strong>：以前要把项目打成 <code>war</code> 包丢进外部 Tomcat 的 <code>webapps</code> 目录下运行。现在 Spring Boot 直接内嵌了 Tomcat，打成 <code>jar</code> 包后直接 <code>java -jar</code> 就能独立运行。</li><li><strong>内置 Actuator 监控</strong>：自带生产级别的健康检查和运行指标监控端点。</li></ol><hr><h3 id="❓-面试官-能详细讲讲-spring-boot-的自动装配原理吗-极其重要-【中高级】" tabindex="-1">❓ 面试官：能详细讲讲 Spring Boot 的自动装配原理吗？（极其重要）【中高级】 <a class="header-anchor" href="#❓-面试官-能详细讲讲-spring-boot-的自动装配原理吗-极其重要-【中高级】" aria-label="Permalink to “❓ 面试官：能详细讲讲 Spring Boot 的自动装配原理吗？（极其重要）【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 自动装配的魔法全在启动类上的 <strong><code>@SpringBootApplication</code></strong> 这个复合注解里。其中最核心的是 <strong><code>@EnableAutoConfiguration</code></strong>。它会在启动时去读取第三方 Jar 包里 <code>META-INF/spring.factories</code> 文件（或 <code>org.springframework.boot.autoconfigure.AutoConfiguration.imports</code> 文件）中配置的各种<strong>自动配置类</strong>，并结合 <strong><code>@Conditional</code></strong> 条件注解，按需将 Bean 注入到 Spring 容器中。</p><p><strong>📝 源码级推演（面试背诵模板）：</strong></p><ol><li><p>拆解 <code>@SpringBootApplication</code>，它包含三个核心子注解：</p><ul><li><code>@SpringBootConfiguration</code>：本质就是 <code>@Configuration</code>，标明这是一个配置类。</li><li><code>@ComponentScan</code>：扫描当前包及子包下的自定义 Bean（如 <code>@Controller</code>）。</li><li><strong><code>@EnableAutoConfiguration</code>（灵魂核心）</strong>。</li></ul></li><li><p>深入 <code>@EnableAutoConfiguration</code>：</p><ul><li>它内部 <code>import</code> 了一个叫 <strong><code>AutoConfigurationImportSelector</code></strong> 的类。</li><li>这个类的 <code>selectImports</code> 方法会在项目启动时执行。</li><li>它会去扫描所有引入的 Jar 包（尤其是 <code>spring-boot-autoconfigure.jar</code>），寻找 <code>META-INF/spring.factories</code> 配置文件。</li><li>从这个文件里，它读取到了上百个全限定名的<strong>自动配置类（XxxAutoConfiguration）</strong>。</li></ul></li><li><p><strong><code>@Conditional</code> 过滤机制（按需加载）</strong>：</p><ul><li>难道这上百个配置类都会被加载吗？绝对不是。</li><li>每个 <code>XxxAutoConfiguration</code> 源码上都打满了 <code>@Conditional</code> 家族注解。</li><li>比如 <code>RedisAutoConfiguration</code> 上有 <code>@ConditionalOnClass(RedisOperations.class)</code>。意思是：<strong>只有当你的 pom.xml 里真实引入了 Redis 的依赖包</strong>，这个配置类才会生效并帮你创建 <code>RedisTemplate</code>。如果你没引，这个配置类就直接跳过。这就是“按需装配”的智慧。</li></ul></li></ol><hr><h3 id="❓-面试官-如果我自己写了一个组件-比如短信发送工具-怎么把它封装成一个-starter-供别人使用-【中高级】" tabindex="-1">❓ 面试官：如果我自己写了一个组件（比如短信发送工具），怎么把它封装成一个 Starter 供别人使用？【中高级】 <a class="header-anchor" href="#❓-面试官-如果我自己写了一个组件-比如短信发送工具-怎么把它封装成一个-starter-供别人使用-【中高级】" aria-label="Permalink to “❓ 面试官：如果我自己写了一个组件（比如短信发送工具），怎么把它封装成一个 Starter 供别人使用？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 自定义 Starter 的核心就是<strong>写一个自动配置类，并把它暴露在 <code>spring.factories</code> 中</strong>。分为四个步骤：引入依赖、写属性类映射 YAML、写自动配置类、配置 <code>spring.factories</code> 或 <code>imports</code> 文件。</p><p><strong>📝 详细实战步骤：</strong></p><ol><li><strong>新建 Maven 工程</strong>：命名规范一般为 <code>sms-spring-boot-starter</code>（官方的都是 <code>spring-boot-starter-xxx</code>）。</li><li><strong>定义 Properties 类</strong>：用 <code>@ConfigurationProperties(prefix = &quot;sms&quot;)</code> 绑定 <code>application.yml</code> 里用户配的账号和密钥。</li><li><strong>编写自动配置类 <code>SmsAutoConfiguration</code></strong>： <ul><li>加上 <code>@Configuration</code> 和 <code>@EnableConfigurationProperties(SmsProperties.class)</code>。</li><li>写一个 <code>@Bean</code> 方法，返回真正的短信发送客户端 <code>SmsClient</code>。</li><li>精髓：加上 <strong><code>@ConditionalOnMissingBean</code></strong>，防止用户自己在业务代码里定义了 <code>SmsClient</code> 被我们覆盖掉（让用户的配置优先级更高）。</li></ul></li><li><strong>暴露配置类（最关键）</strong>： <ul><li>在 <code>src/main/resources/META-INF</code> 目录下新建 <code>spring.factories</code> 文件。</li><li>写入：<code>org.springframework.boot.autoconfigure.EnableAutoConfiguration=com.example.SmsAutoConfiguration</code>。</li><li>（如果是 SpringBoot 2.7+ 推荐用 <code>META-INF/spring/org.springframework.boot.autoconfigure.AutoConfiguration.imports</code> 文件直接按行写类名）。</li></ul></li><li><strong>打包发布</strong>：打成 jar 包给别的项目引用即可自动生效。</li></ol>',19)])])}const m=r(n,[["render",s]]);export{u as __pageData,m as default};
